(window.webpackJsonp=window.webpackJsonp||[]).push([[360],{987:function(n,e){n.exports="\x3c!-- \ntitle: Webpack入门\nsort: \n--\x3e \n\n> `yarn add webpack webpack-cli`\n>\n> 用于打包编译代码\n\n## 入门\n\n1. 配置文件`webpack.config.js`\n\n```js\n'use strict'\nconst path = require('path');\nmodule.exports = {\n  // 打包入口\n  entry: {\n    index: './src/index.js',\n  },\n  // 输出地址\n  output: {\n    path: path.join(__dirname, 'dist'),\n    filename: 'index.js'\n  },\n  // 开发环境\n  mode: 'production',\n}\n```\n\n2. 源代码`src`\n\n```js\n// 目录树\n|- dist\n   |- index.html\n|- src\n   |- index.js\n   |- sayhi.js\n\n\n// sayhi.js\nexport function sayHi() {\n  return 'Hello Webpack~'\n}\n// index.js\nimport {sayHi} from './sayhi'\ndocument.write(sayHi())\n```\n\n3. 引用代码`dist/index.html`\n\n```html\n<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n    <meta charset=\"UTF-8\">\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\">\n    <title>Document</title>\n</head>\n<body>\n    <script src=\"./index.js\" type=\"text/javascript\"><\/script>\n</body>\n</html>\n```\n\n4. 编译\n\n```bash\n# 不够优雅的方法\n./node_modules/.bin/webpack\n\n# package.json添加\n\"build\": \"webpack\"\n# 运行\nnpm run build\n\n```\n\n### 绑定处理函数\n\n```js\nfunction onClick(id, callback) {\n    document.querySelector(`#${id}`).addEventListener('click',callback)\n}\n\nonClick('move-to-left',function () {\n    moveToLeft()\n})\n```\n\n### 编译ES6\n\n```\nyarn add @babel/core @babel/preset-env babel-loader \n```\n\n- `.babelrc`\n\n  ```json\n  {\n      \"presets\": [\n          \"@babel/preset-env\",\n      ]\n  }\n  ```\n\n- `webpack.config.js`\n\n  ```js\n  module: {\n          rules: [\n              {\n                  test: /.js$/,\n                  use: 'babel-loader'\n              },\n           ]\n        }\n  ```\n\n### 引入css\n\n> `npm i style-loader css-loader -D`\n\n1. 配置文件\n\n```json\nmodule: {\n  rules: [\n    {\n      test: /.css$/,\n      use: [\n        'style-loader',\n        'css-loader'\n      ]\n    },\n  ]\n},\n```\n\n2. 添加css文件，执行编译命令\n\n```js\n// 在js中引入css\nimport './style.css'\n```\n\n"}}]);